import { SourceFrequency } from '@domain/entry';
import { tw } from '@utils/useTailwind';
import { clsx } from 'clsx';
import { useTranslation } from 'react-i18next';
import { Checkbox } from '../../../Checkbox';
import { Label } from '../../../Label';

type Props = {
  displayFrequencyAsCheckbox?: boolean;
  frequency: SourceFrequency;
  isChecked: boolean;
  message?: string | null;
  onClick?: () => void;
};

export const RecurringUpgradeBanner = ({
  displayFrequencyAsCheckbox,
  frequency,
  isChecked,
  message,
  onClick,
}: Props) => {
  const { t } = useTranslation('actionPagesBuilder', {
    keyPrefix: 'designer.finance.recurringUpgradeBanner',
  });
  const bannerClasses = clsx(
    !displayFrequencyAsCheckbox || isChecked
      ? 'border-yellow-500 bg-yellow-200'
      : 'border-yellow-400 bg-neutral-0',
    displayFrequencyAsCheckbox ? 'cursor-pointer' : 'cursor-default',
    tw`flex w-full flex-col gap-4 rounded-md border p-4`
  );
  return (
    <div
      className={bannerClasses}
      data-checked={isChecked ? '' : undefined}
      id="recurring-upgrade-banner"
    >
      {message && <Label className="leading-[25.5px]">{message}</Label>}
      {displayFrequencyAsCheckbox && (
        <Checkbox
          className="flex-start flex"
          isChecked={isChecked}
          name="recurring-upgrade"
          onChange={onClick}
          onClick={(e: React.MouseEvent) => {
            onClick?.();
            e.preventDefault();
          }}
          value="0"
          variant="darkCheckbox"
        >
          <Label variant="regular">{t('bannerText', { frequency })}</Label>
        </Checkbox>
      )}
    </div>
  );
};

